// src/pages/Chat.jsx
import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { friendsAPI } from '../services/api';
import api from '../services/api';
import toast from 'react-hot-toast';
import './Chat.css';

// ── Chat List ─────────────────────────────────────────
function ChatList({ rooms, onSelect, selectedId }) {
  const timeAgo = (d) => {
    if (!d) return '';
    const m = Math.floor((Date.now() - new Date(d)) / 60000);
    if (m < 1)  return 'now';
    if (m < 60) return `${m}m`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}h`;
    return `${Math.floor(h/24)}d`;
  };

  return (
    <div className="chat-list">
      <div className="chat-list-header">
        <h2>💬 Messages</h2>
      </div>
      {rooms.length === 0 ? (
        <div className="chat-empty-list">
          <div style={{fontSize:40}}>💬</div>
          <p>No chats yet!</p>
          <p style={{fontSize:12}}>Add friends to start chatting</p>
        </div>
      ) : (
        rooms.map(r => (
          <button
            key={r.room_id}
            className={`chat-room-btn ${selectedId === r.room_id ? 'active' : ''}`}
            onClick={() => onSelect(r)}
          >
            <div className="avatar avatar-md" style={{background: r.avatar_color||'#FFE5E5'}}>
              {r.avatar_emoji||'🦊'}
            </div>
            <div className="chat-room-info">
              <div className="chat-room-name">{r.display_name}</div>
              <div className="chat-room-last">
                {r.last_message?.slice(0,32) || 'Say hi! 👋'}
                {r.last_message?.length > 32 ? '...' : ''}
              </div>
            </div>
            <div className="chat-room-meta">
              <div className="chat-room-time">{timeAgo(r.last_message_time)}</div>
              {r.unread_count > 0 && (
                <div className="chat-unread">{r.unread_count}</div>
              )}
            </div>
          </button>
        ))
      )}
    </div>
  );
}

// ── Chat Window ───────────────────────────────────────
function ChatWindow({ friend, roomId, currentUser, onBack }) {
  const [messages, setMessages] = useState([]);
  const [input,    setInput]    = useState('');
  const [sending,  setSending]  = useState(false);
  const [polling,  setPolling]  = useState(null);
  const bottomRef = useRef();
  const inputRef  = useRef();

  useEffect(() => {
    loadMessages();
    // Poll for new messages every 3 seconds
    const p = setInterval(loadMessages, 3000);
    setPolling(p);
    return () => clearInterval(p);
  }, [friend.id]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const loadMessages = async () => {
    try {
      const { data } = await api.get(`/chat/${friend.id}`);
      setMessages(data.data.messages);
    } catch {}
  };

  const sendMessage = async (e) => {
    e.preventDefault();
    if (!input.trim()) return;
    setSending(true);
    const text = input.trim();
    setInput('');

    // Optimistic update
    const tempMsg = {
      id: Date.now(),
      content: text,
      sender_id: currentUser.id,
      created_at: new Date().toISOString(),
      display_name: currentUser.display_name,
      avatar_emoji: currentUser.avatar_emoji,
      avatar_color: currentUser.avatar_color,
      temp: true,
    };
    setMessages(prev => [...prev, tempMsg]);

    try {
      const { data } = await api.post(`/chat/${friend.id}`, { content: text });
      setMessages(prev => prev.map(m => m.temp ? data.data.message : m));
    } catch (err) {
      toast.error('Could not send message');
      setMessages(prev => prev.filter(m => !m.temp));
      setInput(text);
    } finally {
      setSending(false);
      inputRef.current?.focus();
    }
  };

  const formatTime = (d) => new Date(d).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'});

  const groupedMessages = messages.reduce((groups, msg, i) => {
    const prev = messages[i - 1];
    const showAvatar = !prev || prev.sender_id !== msg.sender_id;
    groups.push({ ...msg, showAvatar });
    return groups;
  }, []);

  return (
    <div className="chat-window">
      {/* Header */}
      <div className="chat-win-header">
        <button className="chat-back" onClick={onBack}>←</button>
        <div className="avatar avatar-md" style={{background: friend.avatar_color||'#FFE5E5'}}>
          {friend.avatar_emoji||'🦊'}
        </div>
        <div className="chat-win-info">
          <div className="chat-win-name">{friend.display_name}</div>
          <div className="chat-win-status">@{friend.username}</div>
        </div>
      </div>

      {/* Messages */}
      <div className="chat-messages">
        {messages.length === 0 && (
          <div className="chat-start">
            <div className="avatar avatar-xl" style={{background: friend.avatar_color||'#FFE5E5', margin:'0 auto 12px'}}>
              {friend.avatar_emoji||'🦊'}
            </div>
            <p>Say hi to <strong>{friend.display_name}</strong>! 👋</p>
          </div>
        )}
        {groupedMessages.map(msg => {
          const isMe = msg.sender_id === currentUser.id;
          return (
            <div key={msg.id} className={`msg-row ${isMe ? 'me' : 'them'}`}>
              {!isMe && msg.showAvatar && (
                <div className="avatar avatar-sm msg-avatar" style={{background: friend.avatar_color||'#FFE5E5'}}>
                  {friend.avatar_emoji||'🦊'}
                </div>
              )}
              {!isMe && !msg.showAvatar && <div style={{width:36}} />}
              <div className="msg-bubble-wrap">
                <div className={`msg-bubble ${isMe ? 'msg-me' : 'msg-them'} ${msg.temp ? 'msg-sending' : ''}`}>
                  {msg.content}
                </div>
                {msg.showAvatar && (
                  <div className={`msg-time ${isMe ? 'msg-time-right' : ''}`}>
                    {formatTime(msg.created_at)}
                  </div>
                )}
              </div>
            </div>
          );
        })}
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <form className="chat-input-bar" onSubmit={sendMessage}>
        <input
          ref={inputRef}
          className="chat-input"
          placeholder={`Message ${friend.display_name}...`}
          value={input}
          onChange={e => setInput(e.target.value)}
          maxLength={1000}
          autoComplete="off"
        />
        <button className="chat-send" type="submit" disabled={sending || !input.trim()}>
          {sending ? <span className="spinner" style={{width:18,height:18,borderWidth:2}} /> : '➤'}
        </button>
      </form>
    </div>
  );
}

// ── Main Chat Page ────────────────────────────────────
export default function Chat() {
  const { user }   = useAuth();
  const { friendId } = useParams();
  const navigate   = useNavigate();
  const [rooms,    setRooms]    = useState([]);
  const [selected, setSelected] = useState(null);
  const [friend,   setFriend]   = useState(null);
  const [loading,  setLoading]  = useState(true);

  useEffect(() => { loadRooms(); }, []);

  useEffect(() => {
    if (friendId) openChat(parseInt(friendId));
  }, [friendId]);

  const loadRooms = async () => {
    try {
      const { data } = await api.get('/chat');
      setRooms(data.data.rooms);
    } catch { toast.error('Could not load chats'); }
    finally { setLoading(false); }
  };

  const openChat = async (fId) => {
    try {
      const { data } = await api.get(`/chat/${fId}`);
      setFriend(data.data.friend);
      setSelected({ room_id: data.data.room_id, other_id: fId });
      navigate(`/chat/${fId}`, { replace: true });
    } catch (err) { toast.error(err.response?.data?.message || 'Cannot open chat'); }
  };

  const handleRoomSelect = (room) => {
    openChat(room.other_id);
  };

  return (
    <div className="chat-page page-enter">
      <div className="chat-layout">
        <ChatList
          rooms={rooms}
          onSelect={handleRoomSelect}
          selectedId={selected?.room_id}
        />
        {friend && selected ? (
          <ChatWindow
            friend={friend}
            roomId={selected.room_id}
            currentUser={user}
            onBack={() => { setSelected(null); setFriend(null); navigate('/chat'); loadRooms(); }}
          />
        ) : (
          <div className="chat-placeholder">
            <div style={{fontSize:64}}>💬</div>
            <h3>Select a chat</h3>
            <p>Choose a friend from the list to start chatting!</p>
          </div>
        )}
      </div>
    </div>
  );
}
